var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드레카… 가, 가져왔어….","JPN":"ドレカ……も、持ってきたよ……","ENG":"Dreka... I-I brought it...","TWN":"德蕾卡……我拿來了……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"응, 고생 많았어 언니.","JPN":"うん。お疲れ、姉さん。","ENG":"Okay. Good work, sis.","TWN":"好喔～辛苦了呢，姊姊。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"많이 힘들었지?","JPN":"大変だったよね？","ENG":"It was pretty hard, right?","TWN":"你很累吧？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"……난 괜찮아.","JPN":"……私は大丈夫。","ENG":"...I'm fine.","TWN":"……我沒事。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흠… 사샤언니의 핵은 이렇게 생겼구나.","JPN":"ふーん……サシャさんの核はこんな形をしてるんだ。","ENG":"Hmm... So this is what Sasha's core looks like.","TWN":"嗯……莎夏姊姊的核心是這樣的啊。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"역시 특이해. 보통 그림자 핵은 무서운 느낌이 드는데, 이건 달라.","JPN":"やっぱり変わってる。普通シャドウの核って怖い感じがするのに、これは違うね。","ENG":"It's so unique. Normally, Shadow Cores look scary, but this one's different.","TWN":"果然很特別，一般的暗影核心會讓人害怕，但姊姊不一樣。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"만지고 있으면 <color=#ffd34c>상냥한 느낌</color>이 전해져. 이런 건 처음 봐.","JPN":"触ってると<color=#ffd34c>優しさ</color>が伝わってくる。こんなの初めて見たよ。","ENG":"When I touch it, I get a <color=#ffd34c>kind feeling</color>. I’ve never seen anything like this before.","TWN":"摸著它有種<color=#ffd34c>溫柔的感覺</color>。這種情況還是第一次遇到呢。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"마브카 언니가 정말 부러워. 이런 핵을 평생 가지고 살아가는 거잖아.","JPN":"マブカさんが本当にうらやましいなあ。一生こんな核を持って生きていくんでしょう？","ENG":"I envy Mavka. She gets to live with this core forever.","TWN":"真羡慕瑪卡姊姊，能一輩子擁有這樣的核心。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어라? 이상한 기계가 붙어있네. 여긴 그림자 핵을 장착시킬 부위인데…","JPN":"あれ？　変な機械がついてる。ここはシャドウの核を取り付ける部分なんだけど……","ENG":"Huh? There's an odd device attached in here. But this is where the Shadow Core should go.","TWN":"咦？有個奇怪的東西，這是放置暗影核心的部位……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"녹음기구나. 사샤 언니가 남겨준 걸까?","JPN":"録音機だね。サシャさんが残してくれたのかな？","ENG":"It's a recorder. Did Sasha give it to her?","TWN":"錄音機？是莎夏姊姊留下的嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 사샤언니의 유품과 함께 붙여놓으면 더 볼만할 거야.","JPN":"ひひっ。サシャさんの遺品と一緒に置いておけばもっと見栄えがしそうだね。","ENG":"Hehe, it'll be even better if it's next to Sasha's keepsake.","TWN":"嘻嘻，和莎夏姊姊的遺物放在一起，好像更有看頭。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"이, 이제… 어쩔 생각이야?","JPN":"こ、これから……どうするつもりなの？","ENG":"N-now... what are you going to do?","TWN":"德，德蕾卡……你現在想要做什麼？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"음… 한번 맞춰볼래?","JPN":"うーん……当ててみる？","ENG":"Hmm... Why don't you take a guess?","TWN":"嗯……你猜猜看？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드, 드레카! 너 설마…?!","JPN":"ド、ドレカ！　あなた、まさか……！？","ENG":"D-Dreka! You're not going to...?!","TWN":"德，德萊卡！你該不會是……？！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"우리 마브카 언니는 곧 그림자 핵과 융합한 <color=#ffd34c>최초의 인형</color>이 될 거야.","JPN":"マブカさんは、もうすぐシャドウの核と融合した<color=#ffd34c>最初の人形</color>になるよ。","ENG":"Mavka will soon become the <color=#ffd34c>first Doll</color> to be fused with a Shadow Core.","TWN":"瑪卡姊姊很快就會成為與暗影核心融合的<color=#ffd34c>第一個娃娃</color>。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"사샤 언니의 능력과 그림자의 힘, 마트료시카 인형의 기술력까지 합해지면…","JPN":"サシャさんの能力にシャドウの力、マトリョシカ人形の技術力まで加わったら……","ENG":"By combining Sasha's ability, a Shadow's strength, and the technology of Matryoshka Dolls...","TWN":"如果把莎夏姊姊的能力、暗影的力量和娃娃的技術結合起來……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"우리 북방합의체는 최강의 전력을 얻게 되는거지!","JPN":"私たち北方合意体は、最強の戦力を手に入れることになるの！","ENG":"the Northern Union will have the strongest unit!","TWN":"北方和議會就會獲得有史以來最強的戰力！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"하, 하지만 우리가 그림자를 제어 할 수 있을리가…!","JPN":"で、でも私たちにシャドウを制御できるわけ……！","ENG":"B-but there's no way we can control a Shadow–!","TWN":"但，但是我們不可能控制暗影啊……！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그림자의 핵을 장착하다니… 난 들어본 적도 없는데….","JPN":"シャドウの核を装着するなんて……私、聞いたこともない……","ENG":"Installing a Shadow Core... I've never heard of such a thing...","TWN":"裝上暗影核心……我從來沒聽說過這種事……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래서 최초라고 말한거야 언니.","JPN":"だから最初って言ったのよ、姉さん。","ENG":"That's why I said she's the first, sis.","TWN":"所以才說是第一個嘛，姊姊。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"상냥하신 우리 박사님께서는 우리가 희생되길 원치 않으셨나봐.","JPN":"優しい博士は、私たちに犠牲になってほしくなかったみたい。","ENG":"I guess our kind doctor didn't want to sacrifice us.","TWN":"我們親愛的博士似乎還不希望犧牲我們。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"시린그라드… 북방합의체에 거역하는 못된 마을.","JPN":"シリングラード……北方合意体に逆らう目障りな村。","ENG":"Ciringrad... the wicked village that rebels against the Northern Union.","TWN":"錫林格勒……這個膽敢違抗北方和議會的村子。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이런 곳은 우리가 어떤 짓을 해도, 용서받을 수 있다구.","JPN":"あんな場所は私たちが何をしても、許されるんだよ。","ENG":"I'm sure we'll be forgiven no matter what we do here.","TWN":"在這種地方，不管我們做什麼，都會被原諒。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"설령 잘못 되더라도 아픈건 내가 다 받아줄 테니까, 언니는 걱정하지 않아도 돼.","JPN":"たとえ失敗しても痛みは私が全部引き受けてあげるから、姉さんは心配しなくていいの。","ENG":"Even if something goes wrong, I'll take all the pain, so don't worry, sis.","TWN":"即使出了問題，痛苦我會全部承擔，姊姊你不用擔心喔。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"난 언니의 하나뿐인 동생이잖아?","JPN":"私は姉さんのたった一人の妹でしょう？","ENG":"I'm your one and only little sister, right?","TWN":"我是你唯一的妹妹，不是嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"안돼 드레카. 제발…!","JPN":"ダメ、ドレカ。お願い……！","ENG":"No, Dreka. Please...!","TWN":"不行，德蕾卡，求你了……！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};